def fibonacci(n):
    if n < 0:
        raise ValueError("Input must be a non-negative integer")
    if n <= 1:
        return n

    def _fast_double(n):
        if n == 0:
            return (0, 1)
        k, r = divmod(n, 2)
        fk, fk1 = _fast_double(k)
        # F(2k) = F(k) * (2*F(k+1) - F(k))
        # F(2k+1) = F(k)^2 + F(k+1)^2
        f2k = fk * (2 * fk1 - fk)
        f2k1 = fk * fk + fk1 * fk1
        if r:
            return (f2k1, f2k + f2k1)
        return (f2k, f2k1)

    return _fast_double(n)[0]

def fibonacci(n):
    if n < 0:
        raise ValueError("Input must be a non-negative integer")
    if n <= 1:
        return n

    a, b = 0, 1  # F(0), F(1)

    # Process bits from MSB to LSB
    for i in range(n.bit_length() - 1, -1, -1):
        # Doubling step
        c = a * ((b << 1) - a)   # F(2k)
        d = a * a + b * b         # F(2k+1)

        if (n >> i) & 1:
            a, b = d, c + d       # Shift to F(2k+1), F(2k+2)
        else:
            a, b = c, d           # Stay at F(2k), F(2k+1)

    return a

